class Solution:
    def minMutation(self, startGene: str, endGene: str, bank: List[str]) -> int:
        bank = set(bank)
        if endGene not in bank: return -1
        q = deque([(startGene, 0)])
        seen = {startGene}
        genes = "ACGT"
        while q:
            g, d = q.popleft()
            if g == endGene: return d
            for i in range(len(g)):
                for c in genes:
                    if c == g[i]: continue
                    ng = g[:i] + c + g[i+1:]
                    if ng in bank and ng not in seen:
                        seen.add(ng); q.append((ng, d+1))
        return -1

